var src = inputs[0];
var color = GetColor(parameters, "color", System.Windows.Media.Color.FromRgb(40, 200, 220));
var scanIntensity = GetFloat(parameters, "scanlineStrength", 0.3f);
var flicker = GetFloat(parameters, "flicker", 0.2f);
var chromShift = GetFloat(parameters, "colorShift", 0.3f);
var opacity = GetFloat(parameters, "opacity", 0.7f);
var seed = GetInt(parameters, "seed", context.Seed);
var size = context.TileSize;
var result = new PixelBuffer(size, size);
var hR = color.R / 255f; var hG = color.G / 255f; var hB = color.B / 255f;
result.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;
    // Source color (with chromatic shift)
    float sR = 0.5f, sG = 0.5f, sB = 0.5f;
    if (src != null)
    {
        var shiftPx = (int)(chromShift * size * 0.03f);
        var (r0, _, _, _) = src.GetPixel(Math.Clamp(x + shiftPx, 0, size-1), y);
        var (_, g0, _, _) = src.GetPixel(x, y);
        var (_, _, b0, _) = src.GetPixel(Math.Clamp(x - shiftPx, 0, size-1), y);
        sR = r0; sG = g0; sB = b0;
    }
    // Scanlines
    var scan = 1f - scanIntensity * (MathF.Sin(v * size * MathF.PI * 0.5f) * 0.5f + 0.5f);
    // Flicker noise
    var flickNoise = 1f - flicker * HashToUnit(x, y, seed ^ 777) * 0.3f;
    // Tint with holo color
    var lum = 0.2126f * sR + 0.7152f * sG + 0.0722f * sB;
    var r = lum * hR * scan * flickNoise;
    var g = lum * hG * scan * flickNoise;
    var b = lum * hB * scan * flickNoise;
    result.SetPixel(x, y, Math.Clamp(r,0,1), Math.Clamp(g,0,1), Math.Clamp(b,0,1), opacity);
});
return result;
